package main

import "testing"

var BenchmarkString1 = ""
var BenchmarkString2 = ""

func TestPermutationString(t *testing.T) {
	tests := []struct {
		name   string
		sting1 string
		sting2 string
		want   bool
	}{
		{
			name:   "Test 1",
			sting1: "abc",
			sting2: "lecabee",
			want:   true,
		},
		{
			name:   "Test 2",
			sting1: "abc",
			sting2: "lecaabee",
			want:   false,
		},
		{
			name:   "Test 3",
			sting1: "",
			sting2: "",
			want:   false,
		},
		{
			name:   "Test 4",
			sting1: BenchmarkString1,
			sting2: BenchmarkString2,
			want:   true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name+" Brute Force", func(t *testing.T) {
			got := checkInclusionBruteForce(tt.sting1, tt.sting2)
			if got != tt.want {
				t.Errorf("got %v, want %v", got, tt.want)
			}
		})

		t.Run(tt.name+" Sliding Window", func(t *testing.T) {
			got := checkInclusionSlidingWindow(tt.sting1, tt.sting2)
			if got != tt.want {
				t.Errorf("got %v, want %v", got, tt.want)
			}
		})

		t.Run(tt.name+" Sliding Window Hash Map", func(t *testing.T) {
			got := checkInclusionSlidingWindowHashMap(tt.sting1, tt.sting2)
			if got != tt.want {
				t.Errorf("got %v, want %v", got, tt.want)
			}
		})
	}
}

func BenchmarkCheckInclusion(b *testing.B) {
	sting1 := BenchmarkString1
	sting2 := BenchmarkString2

	b.Run("Brute Force", func(b *testing.B) {
		b.ResetTimer()
		for b.Loop() {
			checkInclusionBruteForce(sting1, sting2)
		}
	})
	b.Run("Sliding Window", func(b *testing.B) {
		b.ResetTimer()
		for b.Loop() {
			checkInclusionSlidingWindow(sting1, sting2)
		}
	})
	b.Run("Sliding Window Hash Map", func(b *testing.B) {
		b.ResetTimer()
		for b.Loop() {
			checkInclusionSlidingWindowHashMap(sting1, sting2)
		}
	})
}
